sql:
SELECT DISTINCT users.user_name, users.role
FROM users
INNER JOIN signal_comments ON users.user_id = signal_comments.user_id;

SELECT signal_name, format, sample_rate, bit_depth, duration, uploaded_by, status
FROM audio_signals
WHERE status = 'active';

SELECT user_name
FROM users
WHERE user_id = (
    SELECT uploaded_by
    FROM audio_signals
    WHERE duration = (
        SELECT MAX(duration)
        FROM audio_signals
    )
);

SELECT signal_name, upload_date, last_modified
FROM audio_signals
WHERE uploaded_by = 1 AND status = 'active' AND last_modified > '2022-12-31';

SELECT signal_id
FROM signal_ratings
WHERE rating = 5;

external_knowledge:
- "melodic tales" refers to audio signals;
- "audio weavers" refers to users with the role of 'audio engineer';
- "travel at a majestic pace" refers to having a sample rate of 48 kHz or higher;
- "minimum voyage of a minute" refers to a duration of 60 seconds or longer;
- "sanctuaries of clarity and richness" refers to audio signals with a bit depth of 24 bits or higher;
- "etched into the annals of our records" refers to the active status of the audio signals.

