SELECT user_name
FROM users
WHERE user_id = 1;

SELECT uploaded_by, COUNT(signal_id) AS total_signals
FROM audio_signals
GROUP BY uploaded_by;

SELECT signal_name, format
FROM audio_signals
WHERE duration = (SELECT MAX(duration) FROM audio_signals);
